/*  Mentova — ARC-AGI-1 Full Benchmark Runner  (Acc_71, extended Acc_75)

    Runs all 400 public ARC-AGI-1 training tasks through Mentova's
    inductive reasoning engine and reports an honest score.

    Methodology: pure induction from examples, no pretraining on the
    ARC-AGI-1 corpus, transformation rule named glass-box for every
    solved task.  Raw score reported as N/400 and as a percentage.

    Two search levels are tried in order for each task:
        Level 1 (single): find one named rule R such that
            arc_transform(R, In, Out) for every training pair.
        Level 2 (composite): find an ordered pair (R1, R2) such that
            arc_transform(R1, In, Mid), arc_transform(R2, Mid, Out)
            for every training pair.

    The ARC-AGI-1 public training set (Chollet 2019) is stored as
    Prolog facts in data/arc_agi_1/arc_tasks.pl, generated by
    tools/arc_agi_to_prolog.py.

    Predicate interface:
        arc_benchmark_run(-Score, -Total, -Results)
            Run the full benchmark.  Results = list of
            result(TaskId, pass(Rule)) | result(TaskId, fail).
        arc_benchmark_print/0
            Run and print a full report to stdout.
*/

% Declare this file as the arc_benchmark module.
:- module(arc_benchmark, [
    % Export arc_benchmark_run/3 for programmatic use.
    arc_benchmark_run/3,
    % Export arc_benchmark_print/0 for console use.
    arc_benchmark_print/0,
    % Export arc_transform/3 for external testing.
    arc_transform/3,
    % Export arc_named_rule/1 for external enumeration.
    arc_named_rule/1
]).

% Load list utilities needed for grid operations.
:- use_module(library(lists), [
    % member/2 for candidate search.
    member/2,
    % nth1/3 for column extraction.
    nth1/3,
    % numlist/3 for column index generation.
    numlist/3,
    % msort/2 for row sorting.
    msort/2,
    % append/2 for row concatenation.
    append/2,
    % last/2 for last element.
    last/2
]).
% Load apply utilities for maplist, include, and foldl.
:- use_module(library(apply), [maplist/2, maplist/3, include/3, exclude/3, foldl/4]).
% Load aggregate for counting.
:- use_module(library(aggregate), [aggregate_all/3]).

% Allow arc_transform/3 clauses to appear at non-consecutive positions.
:- discontiguous arc_transform/3.
% Allow arc_named_rule/1 to appear at non-consecutive positions.
:- discontiguous arc_named_rule/1.

% ---------------------------------------------------------------------------
% TRANSFORM REGISTRY
% arc_named_rule(+RuleName) — enumerate all known transform names.
% arc_transform(+Rule, +Grid, -OutputGrid) — apply Rule to Grid.
% ---------------------------------------------------------------------------

% --- Geometric transforms ---

% Enumerate reverse_rows as a known rule name.
arc_named_rule(reverse_rows).
% Define reverse_rows: reverse each row left-to-right.
arc_transform(reverse_rows, Grid, Result) :-
    % Apply reverse to every row of the grid.
    maplist([Row, Rev]>>(reverse(Row, Rev)), Grid, Result).

% Enumerate vertical_flip as a known rule name.
arc_named_rule(vertical_flip).
% Define vertical_flip: reverse the order of rows top-to-bottom.
arc_transform(vertical_flip, Grid, Result) :-
    % Reverse the list of rows.
    reverse(Grid, Result).

% Enumerate transpose as a known rule name.
arc_named_rule(transpose).
% Define transpose: swap rows and columns.
arc_transform(transpose, Grid, Result) :-
    % Extract the first row to determine the number of columns.
    Grid = [FirstRow|_],
    % Get the number of columns.
    length(FirstRow, NCols),
    % Build column indices.
    numlist(1, NCols, ColIdxs),
    % For each column index, extract that column from the grid to form a row.
    maplist([CI, Col]>>(maplist([R,E]>>(nth1(CI,R,E)), Grid, Col)), ColIdxs, Result).

% Enumerate rotate_90_cw as a known rule name.
arc_named_rule(rotate_90_cw).
% Define rotate_90_cw: transpose then reverse each row.
arc_transform(rotate_90_cw, Grid, Result) :-
    % Transpose the grid first.
    arc_transform(transpose, Grid, T),
    % Then reverse each row.
    arc_transform(reverse_rows, T, Result).

% Enumerate rotate_90_ccw as a known rule name.
arc_named_rule(rotate_90_ccw).
% Define rotate_90_ccw: reverse each row then transpose.
arc_transform(rotate_90_ccw, Grid, Result) :-
    % Reverse each row first.
    arc_transform(reverse_rows, Grid, T),
    % Then transpose.
    arc_transform(transpose, T, Result).

% Enumerate rotate_180 as a known rule name.
arc_named_rule(rotate_180).
% Define rotate_180: vertical flip then reverse each row.
arc_transform(rotate_180, Grid, Result) :-
    % Flip rows top-to-bottom.
    arc_transform(vertical_flip, Grid, T),
    % Then reverse each row.
    arc_transform(reverse_rows, T, Result).

% Enumerate diagonal_flip as a known rule name.
arc_named_rule(diagonal_flip).
% Define diagonal_flip: transpose then vertical flip (flip across anti-diagonal).
arc_transform(diagonal_flip, Grid, Result) :-
    % Transpose the grid.
    arc_transform(transpose, Grid, T),
    % Then flip vertically.
    arc_transform(vertical_flip, T, Result).

% Enumerate anti_diagonal_flip as a known rule name.
arc_named_rule(anti_diagonal_flip).
% Define anti_diagonal_flip: vertical flip then transpose (other anti-diagonal).
arc_transform(anti_diagonal_flip, Grid, Result) :-
    % Flip vertically.
    arc_transform(vertical_flip, Grid, T),
    % Then transpose.
    arc_transform(transpose, T, Result).

% Enumerate identity as a known rule name.
arc_named_rule(identity).
% Define identity: output = input (some ARC tasks are identity on test).
arc_transform(identity, Grid, Grid).

% --- Gravity transforms ---

% Enumerate gravity_down as a known rule name.
arc_named_rule(gravity_down).
% Define gravity_down: non-zero cells fall to the bottom of each column.
arc_transform(gravity_down, Grid, Result) :-
    % Get grid dimensions.
    length(Grid, NRows),
    Grid = [FirstRow|_],
    length(FirstRow, NCols),
    % Process each column index.
    numlist(1, NCols, ColIdxs),
    maplist([CI,OutCol]>>(
        % Extract column CI from the grid.
        maplist([Row,Cell]>>(nth1(CI,Row,Cell)), Grid, ColCells),
        % Filter to non-zero cells.
        include([C]>>(C \= 0), ColCells, NonZero),
        % Count zeros to prepend.
        length(NonZero, NNZ),
        NZeros is NRows - NNZ,
        % Build result column: zeros then non-zero cells.
        length(Zeros, NZeros),
        maplist(=(0), Zeros),
        append(Zeros, NonZero, OutCol)
    ), ColIdxs, OutCols),
    % Reconstruct rows from columns.
    numlist(1, NRows, RowIdxs),
    maplist([RI,Row]>>(
        maplist([Col,Cell]>>(nth1(RI,Col,Cell)), OutCols, Row)
    ), RowIdxs, Result).

% Enumerate gravity_up as a known rule name.
arc_named_rule(gravity_up).
% Define gravity_up: non-zero cells float to the top of each column.
arc_transform(gravity_up, Grid, Result) :-
    % Get grid dimensions.
    length(Grid, NRows),
    Grid = [FirstRow|_],
    length(FirstRow, NCols),
    % Process each column index.
    numlist(1, NCols, ColIdxs),
    maplist([CI,OutCol]>>(
        % Extract column CI.
        maplist([Row,Cell]>>(nth1(CI,Row,Cell)), Grid, ColCells),
        % Keep non-zero cells.
        include([C]>>(C \= 0), ColCells, NonZero),
        % Compute trailing zeros.
        length(NonZero, NNZ),
        NZeros is NRows - NNZ,
        length(Zeros, NZeros),
        maplist(=(0), Zeros),
        % Non-zero cells go first, then zeros.
        append(NonZero, Zeros, OutCol)
    ), ColIdxs, OutCols),
    % Reconstruct rows.
    numlist(1, NRows, RowIdxs),
    maplist([RI,Row]>>(
        maplist([Col,Cell]>>(nth1(RI,Col,Cell)), OutCols, Row)
    ), RowIdxs, Result).

% Enumerate gravity_left as a known rule name.
arc_named_rule(gravity_left).
% Define gravity_left: non-zero cells slide to the left of each row.
arc_transform(gravity_left, Grid, Result) :-
    % Process each row independently.
    maplist([Row, OutRow]>>(
        % Filter non-zero cells to the front, pad zeros at the end.
        include([C]>>(C \= 0), Row, NonZero),
        length(Row, Len),
        length(NonZero, NNZ),
        NZeros is Len - NNZ,
        length(Zeros, NZeros),
        maplist(=(0), Zeros),
        append(NonZero, Zeros, OutRow)
    ), Grid, Result).

% Enumerate gravity_right as a known rule name.
arc_named_rule(gravity_right).
% Define gravity_right: non-zero cells slide to the right of each row.
arc_transform(gravity_right, Grid, Result) :-
    % Process each row independently.
    maplist([Row, OutRow]>>(
        % Filter non-zero cells, put zeros first.
        include([C]>>(C \= 0), Row, NonZero),
        length(Row, Len),
        length(NonZero, NNZ),
        NZeros is Len - NNZ,
        length(Zeros, NZeros),
        maplist(=(0), Zeros),
        append(Zeros, NonZero, OutRow)
    ), Grid, Result).

% --- Sort transforms ---

% Enumerate sort_rows_asc as a known rule name.
arc_named_rule(sort_rows_asc).
% Define sort_rows_asc: sort rows by ascending sum of cell values.
arc_transform(sort_rows_asc, Grid, Result) :-
    % Tag each row with its sum, sort, then untag.
    maplist([Row, Sum-Row]>>(sumlist(Row, Sum)), Grid, Tagged),
    msort(Tagged, Sorted),
    pairs_values(Sorted, Result).

% Enumerate sort_rows_desc as a known rule name.
arc_named_rule(sort_rows_desc).
% Define sort_rows_desc: sort rows by descending sum of cell values.
arc_transform(sort_rows_desc, Grid, Result) :-
    % Tag each row with negated sum so msort puts largest first.
    maplist([Row, NegSum-Row]>>(sumlist(Row, S), NegSum is -S), Grid, Tagged),
    msort(Tagged, Sorted),
    pairs_values(Sorted, Result).

% --- Scale transforms ---

% Enumerate scale_up(2) as a known rule name.
arc_named_rule(scale_up(2)).
% Define scale_up(2): each cell becomes a 2x2 block.
arc_transform(scale_up(2), Grid, Result) :-
    arc_scale_up_grid(2, Grid, Result).

% Enumerate scale_up(3) as a known rule name.
arc_named_rule(scale_up(3)).
% Define scale_up(3): each cell becomes a 3x3 block.
arc_transform(scale_up(3), Grid, Result) :-
    arc_scale_up_grid(3, Grid, Result).

% Define arc_scale_up_grid/3: expand each cell to an NxN block.
arc_scale_up_grid(N, Grid, Result) :-
    % For each row, expand horizontally by replicating each cell N times.
    maplist([Row, ExpandedRow]>>(
        % Replicate each cell N times within the row.
        maplist([Cell, Copies]>>(
            length(Copies, N),
            maplist(=(Cell), Copies)
        ), Row, CellCopies),
        append(CellCopies, ExpandedRow)
    ), Grid, ExpandedRows),
    % Replicate each expanded row N times vertically.
    maplist([ERow, NRows]>>(
        length(NRows, N),
        maplist(=(ERow), NRows)
    ), ExpandedRows, RowGroups),
    append(RowGroups, Result).

% --- Tile transforms ---

% Enumerate tile(1,2) as a known rule name.
arc_named_rule(tile(1,2)).
% Define tile(1,2): duplicate grid once horizontally (2 copies side by side).
arc_transform(tile(1,2), Grid, Result) :-
    maplist([Row, Doubled]>>(append(Row, Row, Doubled)), Grid, Result).

% Enumerate tile(1,3) as a known rule name.
arc_named_rule(tile(1,3)).
% Define tile(1,3): triple grid horizontally.
arc_transform(tile(1,3), Grid, Result) :-
    maplist([Row, Tripled]>>(append(Row, Row, T1), append(T1, Row, Tripled)), Grid, Result).

% Enumerate tile(2,1) as a known rule name.
arc_named_rule(tile(2,1)).
% Define tile(2,1): duplicate grid once vertically.
arc_transform(tile(2,1), Grid, Result) :-
    append(Grid, Grid, Result).

% Enumerate tile(3,1) as a known rule name.
arc_named_rule(tile(3,1)).
% Define tile(3,1): triple grid vertically.
arc_transform(tile(3,1), Grid, Result) :-
    append(Grid, Grid, T1),
    append(T1, Grid, Result).

% Enumerate tile(2,2) as a known rule name.
arc_named_rule(tile(2,2)).
% Define tile(2,2): 2x2 tiling (2 copies each direction).
arc_transform(tile(2,2), Grid, Result) :-
    arc_transform(tile(1,2), Grid, H),
    arc_transform(tile(2,1), H, Result).

% Enumerate tile(2,3) as a known rule name.
arc_named_rule(tile(2,3)).
% Define tile(2,3): 2 rows by 3 columns of copies.
arc_transform(tile(2,3), Grid, Result) :-
    arc_transform(tile(1,3), Grid, H),
    arc_transform(tile(2,1), H, Result).

% Enumerate tile(3,2) as a known rule name.
arc_named_rule(tile(3,2)).
% Define tile(3,2): 3 rows by 2 columns of copies.
arc_transform(tile(3,2), Grid, Result) :-
    arc_transform(tile(1,2), Grid, H),
    arc_transform(tile(3,1), H, Result).

% Enumerate tile(3,3) as a known rule name.
arc_named_rule(tile(3,3)).
% Define tile(3,3): 3x3 tiling.
arc_transform(tile(3,3), Grid, Result) :-
    arc_transform(tile(1,3), Grid, H),
    arc_transform(tile(3,1), H, Result).

% --- Shift transforms ---

% Enumerate shift_v(2) as a known rule name.
arc_named_rule(shift_v(2)).
% Define shift_v(2): cycle rows upward by 2 positions.
arc_transform(shift_v(2), Grid, Result) :-
    % Take first 2 rows and move them to the end.
    Grid = [R1, R2 | Rest],
    append(Rest, [R1, R2], Result).

% Enumerate shift_v(1) as a known rule name.
arc_named_rule(shift_v(1)).
% Define shift_v(1): cycle rows upward by 1 position.
arc_transform(shift_v(1), Grid, Result) :-
    Grid = [R1 | Rest],
    append(Rest, [R1], Result).

% Enumerate shift_v(3) as a known rule name.
arc_named_rule(shift_v(3)).
% Define shift_v(3): cycle rows upward by 3 positions.
arc_transform(shift_v(3), Grid, Result) :-
    Grid = [R1, R2, R3 | Rest],
    append(Rest, [R1, R2, R3], Result).

% Enumerate shift_h(1) as a known rule name.
arc_named_rule(shift_h(1)).
% Define shift_h(1): cycle each row left by 1 position.
arc_transform(shift_h(1), Grid, Result) :-
    maplist([Row, Shifted]>>(
        Row = [H|T], append(T, [H], Shifted)
    ), Grid, Result).

% Enumerate shift_h(2) as a known rule name.
arc_named_rule(shift_h(2)).
% Define shift_h(2): cycle each row left by 2 positions.
arc_transform(shift_h(2), Grid, Result) :-
    maplist([Row, Shifted]>>(
        Row = [H1,H2|T], append(T, [H1,H2], Shifted)
    ), Grid, Result).

% Enumerate shift_h(3) as a known rule name.
arc_named_rule(shift_h(3)).
% Define shift_h(3): cycle each row left by 3 positions.
arc_transform(shift_h(3), Grid, Result) :-
    maplist([Row, Shifted]>>(
        Row = [H1,H2,H3|T], append(T, [H1,H2,H3], Shifted)
    ), Grid, Result).

% --- Border and interior fill transforms ---

% Helper: arc_fill_border_all(+Color, +Grid, -Result).
arc_fill_border_all(C, Grid, Result) :-
    length(Grid, NRows),
    Grid = [FirstRow|_],
    length(FirstRow, NCols),
    numlist(1, NRows, RowIdxs),
    maplist([RI, OutRow]>>(
        nth1(RI, Grid, InRow),
        numlist(1, NCols, ColIdxs),
        maplist([CI, OutCell]>>(
            nth1(CI, InRow, InCell),
            ( (RI =:= 1 ; RI =:= NRows ; CI =:= 1 ; CI =:= NCols)
            ->  OutCell = C
            ;   OutCell = InCell
            )
        ), ColIdxs, OutRow)
    ), RowIdxs, Result).

% Helper: arc_fill_interior_all(+Color, +Grid, -Result).
arc_fill_interior_all(C, Grid, Result) :-
    length(Grid, NRows),
    Grid = [FirstRow|_],
    length(FirstRow, NCols),
    numlist(1, NRows, RowIdxs),
    maplist([RI, OutRow]>>(
        nth1(RI, Grid, InRow),
        numlist(1, NCols, ColIdxs),
        maplist([CI, OutCell]>>(
            nth1(CI, InRow, InCell),
            ( (RI =:= 1 ; RI =:= NRows ; CI =:= 1 ; CI =:= NCols)
            ->  OutCell = InCell
            ;   OutCell = C
            )
        ), ColIdxs, OutRow)
    ), RowIdxs, Result).

% Generate fill_border(C) transforms for C = 0..9.
arc_named_rule(fill_border(0)). arc_transform(fill_border(0), G, R) :- arc_fill_border_all(0, G, R).
arc_named_rule(fill_border(1)). arc_transform(fill_border(1), G, R) :- arc_fill_border_all(1, G, R).
arc_named_rule(fill_border(2)). arc_transform(fill_border(2), G, R) :- arc_fill_border_all(2, G, R).
arc_named_rule(fill_border(3)). arc_transform(fill_border(3), G, R) :- arc_fill_border_all(3, G, R).
arc_named_rule(fill_border(4)). arc_transform(fill_border(4), G, R) :- arc_fill_border_all(4, G, R).
arc_named_rule(fill_border(5)). arc_transform(fill_border(5), G, R) :- arc_fill_border_all(5, G, R).
arc_named_rule(fill_border(6)). arc_transform(fill_border(6), G, R) :- arc_fill_border_all(6, G, R).
arc_named_rule(fill_border(7)). arc_transform(fill_border(7), G, R) :- arc_fill_border_all(7, G, R).
arc_named_rule(fill_border(8)). arc_transform(fill_border(8), G, R) :- arc_fill_border_all(8, G, R).
arc_named_rule(fill_border(9)). arc_transform(fill_border(9), G, R) :- arc_fill_border_all(9, G, R).

% Generate fill_interior(C) transforms for C = 0..9.
arc_named_rule(fill_interior(0)). arc_transform(fill_interior(0), G, R) :- arc_fill_interior_all(0, G, R).
arc_named_rule(fill_interior(1)). arc_transform(fill_interior(1), G, R) :- arc_fill_interior_all(1, G, R).
arc_named_rule(fill_interior(2)). arc_transform(fill_interior(2), G, R) :- arc_fill_interior_all(2, G, R).
arc_named_rule(fill_interior(3)). arc_transform(fill_interior(3), G, R) :- arc_fill_interior_all(3, G, R).
arc_named_rule(fill_interior(4)). arc_transform(fill_interior(4), G, R) :- arc_fill_interior_all(4, G, R).
arc_named_rule(fill_interior(5)). arc_transform(fill_interior(5), G, R) :- arc_fill_interior_all(5, G, R).
arc_named_rule(fill_interior(6)). arc_transform(fill_interior(6), G, R) :- arc_fill_interior_all(6, G, R).
arc_named_rule(fill_interior(7)). arc_transform(fill_interior(7), G, R) :- arc_fill_interior_all(7, G, R).
arc_named_rule(fill_interior(8)). arc_transform(fill_interior(8), G, R) :- arc_fill_interior_all(8, G, R).
arc_named_rule(fill_interior(9)). arc_transform(fill_interior(9), G, R) :- arc_fill_interior_all(9, G, R).

% --- Color transforms ---

% Helper: apply recolor_nonblack(C) to a grid.
arc_recolor_nonblack(C, Grid, Result) :-
    maplist([Row,Out]>>(
        maplist([Cell,OutCell]>>(
            ( Cell =:= 0 -> OutCell = 0 ; OutCell = C )
        ), Row, Out)
    ), Grid, Result).

% Generate recolor_nonblack(C) for C = 1..9.
arc_named_rule(recolor_nonblack(1)). arc_transform(recolor_nonblack(1), G, R) :- arc_recolor_nonblack(1, G, R).
arc_named_rule(recolor_nonblack(2)). arc_transform(recolor_nonblack(2), G, R) :- arc_recolor_nonblack(2, G, R).
arc_named_rule(recolor_nonblack(3)). arc_transform(recolor_nonblack(3), G, R) :- arc_recolor_nonblack(3, G, R).
arc_named_rule(recolor_nonblack(4)). arc_transform(recolor_nonblack(4), G, R) :- arc_recolor_nonblack(4, G, R).
arc_named_rule(recolor_nonblack(5)). arc_transform(recolor_nonblack(5), G, R) :- arc_recolor_nonblack(5, G, R).
arc_named_rule(recolor_nonblack(6)). arc_transform(recolor_nonblack(6), G, R) :- arc_recolor_nonblack(6, G, R).
arc_named_rule(recolor_nonblack(7)). arc_transform(recolor_nonblack(7), G, R) :- arc_recolor_nonblack(7, G, R).
arc_named_rule(recolor_nonblack(8)). arc_transform(recolor_nonblack(8), G, R) :- arc_recolor_nonblack(8, G, R).
arc_named_rule(recolor_nonblack(9)). arc_transform(recolor_nonblack(9), G, R) :- arc_recolor_nonblack(9, G, R).

% Helper: swap two specific colors in a grid.
arc_swap_colors(A, B, Grid, Result) :-
    maplist([Row,Out]>>(
        maplist([C,OutC]>>(
            ( C =:= A -> OutC = B
            ; C =:= B -> OutC = A
            ; OutC = C
            )
        ), Row, Out)
    ), Grid, Result).

% Helper: recolor one specific color to another.
arc_recolor(From, To, Grid, Result) :-
    maplist([Row,Out]>>(
        maplist([C,OutC]>>(
            ( C =:= From -> OutC = To ; OutC = C )
        ), Row, Out)
    ), Grid, Result).

% Helper: add N to each nonblack cell (modulo 10), color-cycle.
arc_color_cycle(N, Grid, Result) :-
    maplist([Row,Out]>>(
        maplist([C,OutC]>>(
            ( C =:= 0 -> OutC = 0
            ; OutC is ((C - 1 + N) mod 9) + 1
            )
        ), Row, Out)
    ), Grid, Result).

% --- Swap transforms (common color pairs) ---
arc_named_rule(swap(0,1)). arc_transform(swap(0,1), G, R) :- arc_swap_colors(0, 1, G, R).
arc_named_rule(swap(0,2)). arc_transform(swap(0,2), G, R) :- arc_swap_colors(0, 2, G, R).
arc_named_rule(swap(0,3)). arc_transform(swap(0,3), G, R) :- arc_swap_colors(0, 3, G, R).
arc_named_rule(swap(0,4)). arc_transform(swap(0,4), G, R) :- arc_swap_colors(0, 4, G, R).
arc_named_rule(swap(0,5)). arc_transform(swap(0,5), G, R) :- arc_swap_colors(0, 5, G, R).
arc_named_rule(swap(0,6)). arc_transform(swap(0,6), G, R) :- arc_swap_colors(0, 6, G, R).
arc_named_rule(swap(0,7)). arc_transform(swap(0,7), G, R) :- arc_swap_colors(0, 7, G, R).
arc_named_rule(swap(0,8)). arc_transform(swap(0,8), G, R) :- arc_swap_colors(0, 8, G, R).
arc_named_rule(swap(0,9)). arc_transform(swap(0,9), G, R) :- arc_swap_colors(0, 9, G, R).
arc_named_rule(swap(1,2)). arc_transform(swap(1,2), G, R) :- arc_swap_colors(1, 2, G, R).
arc_named_rule(swap(1,3)). arc_transform(swap(1,3), G, R) :- arc_swap_colors(1, 3, G, R).
arc_named_rule(swap(1,4)). arc_transform(swap(1,4), G, R) :- arc_swap_colors(1, 4, G, R).
arc_named_rule(swap(1,5)). arc_transform(swap(1,5), G, R) :- arc_swap_colors(1, 5, G, R).
arc_named_rule(swap(1,6)). arc_transform(swap(1,6), G, R) :- arc_swap_colors(1, 6, G, R).
arc_named_rule(swap(1,7)). arc_transform(swap(1,7), G, R) :- arc_swap_colors(1, 7, G, R).
arc_named_rule(swap(1,8)). arc_transform(swap(1,8), G, R) :- arc_swap_colors(1, 8, G, R).
arc_named_rule(swap(1,9)). arc_transform(swap(1,9), G, R) :- arc_swap_colors(1, 9, G, R).
