            ->  arc_grid_at(Grid, NR9, NC9, Val)
% ERC
            ;   Val = 0
% ERC
            )
% ERC
        ), OutRow)
% ERC
    ), Out),
% ERC
    !.

% move_blocks_up_by_height (5521c0d9): each distinct non-zero value has a
%   row span [R1..R2]; move all its cells up by height = R2-R1+1.
arc_named_rule(move_blocks_up_by_height).
% ERC
arc_transform(move_blocks_up_by_height, Grid, Out) :-
% ERC
    arc_grid_dims(Grid, NR, NC),
% ERC
    NR > 0, NR =< 30, NC > 0, NC =< 30,
% ERC
    numlist(1, NR, AllRows), numlist(1, NC, AllCols),
% ERC
    findall(Vq, (member(Rq, AllRows), member(Cq, AllCols),
% ERC
        arc_grid_at(Grid, Rq, Cq, Vq), Vq \= 0), AllVals),
% ERC
    sort(AllVals, UniqueVals),
% ERC
    UniqueVals \= [],
% ERC
    findall(NewR-C4-V4, (
% ERC
        member(V4, UniqueVals),
% ERC
        findall(RV4, (member(RV4, AllRows),
% ERC
            once((member(CV4, AllCols), arc_grid_at(Grid, RV4, CV4, V4)))), VRows4),
% ERC
        VRows4 \= [],
% ERC
        min_list(VRows4, R1V4), max_list(VRows4, R2V4),
% ERC
        Height4 is R2V4 - R1V4 + 1,
% ERC
        member(R4, AllRows), member(C4, AllCols),
% ERC
        arc_grid_at(Grid, R4, C4, V4),
% ERC
        NewR is R4 - Height4,
% ERC
        NewR >= 1, NewR =< NR
% ERC
    ), MovedCells),
% ERC
    maplist([R, OutRow]>>(
% ERC
        maplist([C, Val]>>(
% ERC
            (   findall(MV, member(R-C-MV, MovedCells), MVs),
% ERC
                MVs = [MV|_]
% ERC
            ->  Val = MV
% ERC
            ;   Val = 0
% ERC
            )
% ERC
        ), AllCols, OutRow)
% ERC
    ), AllRows, Out),
% ERC
    !.

% arc_w26_extend_grid: append rows to Grid using period P and shift S
%   until length reaches 10.
arc_w26_extend_grid(G, NR, NC, P, S, AllCols, Out) :-
% ERC
    (   NR >= 10
% ERC
    ->  length(Out10, 10), append(Out10, _, G), Out = Out10
% ERC
    ;   BaseR is NR - P + 1,
% ERC
        findall(DVal, (
% ERC
            member(DC, AllCols),
% ERC
            SrcC is DC - S,
% ERC
            (   SrcC >= 1, SrcC =< NC
% ERC
            ->  arc_grid_at(G, BaseR, SrcC, DVal)
% ERC
            ;   DVal = 0
% ERC
            )
% ERC
        ), NewRow),
% ERC
        append(G, [NewRow], G1),
% ERC
        NR1 is NR + 1,
% ERC
        arc_w26_extend_grid(G1, NR1, NC, P, S, AllCols, Out)
% ERC
    ).

% extend_periodic_to_10 (53b68214): detect row period P and column shift S;
%   extend pattern to exactly 10 rows.
arc_named_rule(extend_periodic_to_10).
% ERC
arc_transform(extend_periodic_to_10, Grid, Out) :-
% ERC
    arc_grid_dims(Grid, NR, NC),
% ERC
    NR > 0, NR < 10, NC > 0, NC =< 30,
% ERC
    numlist(1, NR, AllRows), numlist(1, NC, AllCols),
% ERC
    once((
% ERC
        Pmax is NR - 1,
% ERC
        Pmax >= 1,
% ERC
        numlist(1, Pmax, PCands),
% ERC
        Sneg is -(NC - 1), Spos is NC - 1,
% ERC
        numlist(Sneg, Spos, SCands),
% ERC
        member(P, PCands),
% ERC
        member(S, SCands),
% ERC
        \+ (
% ERC
            member(Rck, AllRows), Rp is Rck + P, Rp =< NR,
% ERC
            member(Cck, AllCols),
% ERC
            Csrc is Cck - S,
% ERC
            (   Csrc >= 1, Csrc =< NC
% ERC
            ->  arc_grid_at(Grid, Rck, Csrc, Vsrc)
% ERC
            ;   Vsrc = 0
% ERC
            ),
% ERC
            arc_grid_at(Grid, Rp, Cck, Vtgt),
% ERC
            Vsrc \= Vtgt
% ERC
        )
% ERC
    )),
% ERC
    arc_w26_extend_grid(Grid, NR, NC, P, S, AllCols, Out),
% ERC
    !.

% arc_w26_bounce_path: trace billiard path; accumulate visited cells in Acc.
arc_w26_bounce_path(_, _, _, _, _, _, _, 0, Acc, Path) :-
% ERC
    reverse(Acc, Path), !.
% ERC
arc_w26_bounce_path(Grid, NR, NC, R, C, DR, DC, Lim, Acc, Path) :-
% ERC
    Lim > 0,
% ERC
    Acc1 = [R-C|Acc],
% ERC
    NR2 is R+DR, NC2 is C+DC,
% ERC
    (   (NR2 < 1 ; NR2 > NR ; NC2 < 1 ; NC2 > NC)
% ERC
    ->  reverse(Acc1, Path)
% ERC
    ;   arc_grid_at(Grid, NR2, NC2, VN),
% ERC
        (   VN =:= 8
% ERC
        ->  reverse(Acc1, Path)
% ERC
        ;   VN =\= 2
% ERC
        ->  Lim1 is Lim-1,
% ERC
            arc_w26_bounce_path(Grid, NR, NC, NR2, NC2, DR, DC, Lim1, Acc1, Path)
% ERC
        ;   (   arc_grid_at(Grid, NR2, C, 2)
% ERC
            ->  DR2 is -DR
% ERC
            ;   DR2 = DR
% ERC
            ),
% ERC
            (   arc_grid_at(Grid, R, NC2, 2)
% ERC
            ->  DC2 is -DC
% ERC
            ;   DC2 = DC
% ERC
            ),
% ERC
            NR3 is R+DR2, NC3 is C+DC2,
% ERC
            (   NR3 >= 1, NR3 =< NR, NC3 >= 1, NC3 =< NC,
% ERC
                arc_grid_at(Grid, NR3, NC3, V3), V3 \= 2, V3 \= 8
% ERC
            ->  Lim1 is Lim-1,
% ERC
                arc_w26_bounce_path(Grid, NR, NC, NR3, NC3, DR2, DC2, Lim1, Acc1, Path)
% ERC
            ;   reverse(Acc1, Path)
% ERC
            )
% ERC
        )
% ERC
    ).

% billiard_bounce (508bd3b6): 8-cells form directional arrow; ball launches
%   from head forward or tail backward; bounces off 2-cells; stops at OOB/8.
arc_named_rule(billiard_bounce).
% ERC
arc_transform(billiard_bounce, Grid, Out) :-
% ERC
    arc_grid_dims(Grid, NR, NC),
% ERC
    NR > 0, NR =< 30, NC > 0, NC =< 30,
% ERC
    numlist(1, NR, AllRows), numlist(1, NC, AllCols),
% ERC
    findall(R-C, (member(R, AllRows), member(C, AllCols),
% ERC
        arc_grid_at(Grid, R, C, 8)), Eights),
% ERC
    Eights = [E0R-E0C, E1R-E1C | _],
% ERC
    DR is E1R - E0R, DC is E1C - E0C,
% ERC
    last(Eights, HeadR-HeadC),
% ERC
    Eights = [TailR-TailC | _],
% ERC
    FwdR is HeadR + DR, FwdC is HeadC + DC,
% ERC
    (   FwdR >= 1, FwdR =< NR, FwdC >= 1, FwdC =< NC,
% ERC
        arc_grid_at(Grid, FwdR, FwdC, FwdV), FwdV \= 2, FwdV \= 8
% ERC
    ->  StartR = FwdR, StartC = FwdC, DirR = DR, DirC = DC
% ERC
    ;   BwdR is TailR - DR, BwdC is TailC - DC,
% ERC
        BwdR >= 1, BwdR =< NR, BwdC >= 1, BwdC =< NC,
% ERC
        arc_grid_at(Grid, BwdR, BwdC, BwdV), BwdV \= 2, BwdV \= 8,
% ERC
        StartR = BwdR, StartC = BwdC, DirR is -DR, DirC is -DC
% ERC
    ),
% ERC
    Limit is NR * NC + 10,
% ERC
    arc_w26_bounce_path(Grid, NR, NC, StartR, StartC, DirR, DirC, Limit, [], Path),
% ERC
    Path \= [],
% ERC
    maplist([R, OutRow]>>(
% ERC
        maplist([C, Val]>>(
% ERC
            arc_grid_at(Grid, R, C, V0),
% ERC
            (   memberchk(R-C, Path)
% ERC
            ->  Val = 3
% ERC
            ;   Val = V0
% ERC
            )
% ERC
        ), AllCols, OutRow)
% ERC
    ), AllRows, Out),
% ERC
    !.

% ---------------------------------------------------------------------------
% WAVE 27: Eight new rules targeting small unsolved tasks.
% Solves: a740d043, 10fcaaa3, cbded52d, d8c310e9, ce9e57f2,
%         cdecee7f, eb281b96, 72ca375d
% ---------------------------------------------------------------------------

% crop_nonbg_bbox (a740d043): find the most-frequent value as background,
% crop the bounding box of all non-background cells, replace background with 0.
% ERC
arc_named_rule(crop_nonbg_bbox).
% ERC
arc_transform(crop_nonbg_bbox, Grid, Out) :-
% ERC
    arc_grid_dims(Grid, NR, NC),
% ERC
    NR > 0, NR =< 30, NC > 0, NC =< 30,
% ERC
    numlist(1, NR, AllRows), numlist(1, NC, AllCols),
% ERC
    findall(V, (member(R,AllRows), member(C,AllCols),
% ERC
        arc_grid_at(Grid,R,C,V)), AllVals),
% ERC
    msort(AllVals, Sorted),
% ERC
    arc_w27_mode(Sorted, Bg),
% ERC
    findall(R, (member(R,AllRows),
% ERC
        once((member(C,AllCols), arc_grid_at(Grid,R,C,V0), V0 \= Bg))), NZRows),
% ERC
    NZRows \= [],
% ERC
    findall(C, (member(C,AllCols),
% ERC
        once((member(R,AllRows), arc_grid_at(Grid,R,C,V0), V0 \= Bg))), NZCols),
% ERC
    NZCols \= [],
% ERC
    min_list(NZRows, R0), max_list(NZRows, R1),
% ERC
    min_list(NZCols, C0), max_list(NZCols, C1),
% ERC
    numlist(R0, R1, OutRows), numlist(C0, C1, OutCols),
% ERC
    maplist([R, OutRow]>>(
% ERC
        maplist([C, Cell]>>(
% ERC
            arc_grid_at(Grid,R,C,Vc),
% ERC
            (Vc =:= Bg -> Cell = 0 ; Cell = Vc)
% ERC
        ), OutCols, OutRow)
% ERC
    ), OutRows, Out),
% ERC
    !.

% arc_w27_mode(+SortedList, -Mode): returns most frequent element in sorted list.
% ERC
arc_w27_mode([H|T], Mode) :-
% ERC
    arc_w27_mode_(T, H, 1, H, 1, Mode).
% ERC
arc_w27_mode_([], _Cur, _CurCnt, BestVal, _BestCnt, BestVal).
% ERC
arc_w27_mode_([H|T], Cur, CurCnt, BestVal, BestCnt, Mode) :-
% ERC
    (   H =:= Cur
% ERC
    ->  CurCnt1 is CurCnt + 1,
% ERC
        (   CurCnt1 > BestCnt
% ERC
        ->  arc_w27_mode_(T, H, CurCnt1, H, CurCnt1, Mode)
% ERC
        ;   arc_w27_mode_(T, H, CurCnt1, BestVal, BestCnt, Mode)
% ERC
        )
% ERC
    ;   arc_w27_mode_(T, H, 1, BestVal, BestCnt, Mode)
% ERC
    ).

% tile_2x_diag_mark (10fcaaa3): tile grid 2x in both dimensions; replace each
% zero cell with 8 if any diagonal neighbor in the tiled grid is non-zero.
% ERC
arc_named_rule(tile_2x_diag_mark).
% ERC
arc_transform(tile_2x_diag_mark, Grid, Out) :-
% ERC
    arc_grid_dims(Grid, NR, NC),
% ERC
    NR > 0, NR =< 15, NC > 0, NC =< 15,
% ERC
    NR2 is 2*NR, NC2 is 2*NC,
% ERC
    numlist(1, NR2, AllRows2), numlist(1, NC2, AllCols2),
% ERC
    maplist([R, OutRow]>>(
% ERC
        maplist([C, Cell]>>(
% ERC
            Ro is ((R-1) mod NR) + 1, Co is ((C-1) mod NC) + 1,
% ERC
            arc_grid_at(Grid, Ro, Co, V),
% ERC
            (   V =\= 0
% ERC
            ->  Cell = V
% ERC
            ;   (   once((
% ERC
                    member(DR, [-1,1]), member(DC, [-1,1]),
% ERC
                    R2 is R+DR, C2 is C+DC,
% ERC
                    R2 >= 1, R2 =< NR2, C2 >= 1, C2 =< NC2,
% ERC
                    Ro2 is ((R2-1) mod NR) + 1, Co2 is ((C2-1) mod NC) + 1,
% ERC
                    arc_grid_at(Grid, Ro2, Co2, V2), V2 \= 0
% ERC
                ))
% ERC
                ->  Cell = 8
% ERC
                ;   Cell = 0
% ERC
                )
% ERC
            )
% ERC
        ), AllCols2, OutRow)
% ERC
    ), AllRows2, Out),
% ERC
    !.

% sep_grid_propagate (cbded52d): grid divided by all-zero separator rows and cols
% into rectangular blocks. Markers (non-bg, non-0 values) at within-cell position
% (Wr,Wc) propagate to all blocks in the same row-band when 2+ col-bands share them,
% and to all blocks in the same col-band when 2+ row-bands share them.
% ERC
arc_named_rule(sep_grid_propagate).
% ERC
arc_transform(sep_grid_propagate, Grid, Out) :-
% ERC
    arc_grid_dims(Grid, NR, NC),
% ERC
    NR > 0, NR =< 30, NC > 0, NC =< 30,
% ERC
    numlist(1, NR, AllRows), numlist(1, NC, AllCols),
% ERC
    findall(Sr, (member(Sr,AllRows),
% ERC
        \+((member(Sc,AllCols), arc_grid_at(Grid,Sr,Sc,SV), SV \= 0))), SepRows),
% ERC
    findall(Sc, (member(Sc,AllCols),
% ERC
        \+((member(Sr,AllRows), arc_grid_at(Grid,Sr,Sc,SV), SV \= 0))), SepCols),
% ERC
    arc_w27_bands(SepRows, NR, RowBands),
% ERC
    arc_w27_bands(SepCols, NC, ColBands),
% ERC
    RowBands \= [], ColBands \= [],
% ERC
    findall(NSV, (member(NSR,AllRows), \+member(NSR,SepRows),
% ERC
        member(NSC,AllCols), \+member(NSC,SepCols),
% ERC
        arc_grid_at(Grid,NSR,NSC,NSV), NSV \= 0), NonSepVals),
% ERC
    msort(NonSepVals, NonSepSorted),
% ERC
    arc_w27_mode(NonSepSorted, Bg),
% ERC
    findall(Rbi-Cbi-Wr-Wc-MV, (
% ERC
        nth0(Rbi, RowBands, RBand), nth0(Cbi, ColBands, CBand),
% ERC
        nth0(Wr, RBand, MR), nth0(Wc, CBand, MC),
% ERC
        arc_grid_at(Grid,MR,MC,MV), MV \= 0, MV \= Bg
% ERC
    ), Markers),
% ERC
    maplist([R, OutRow]>>(
% ERC
        maplist([C, Cell]>>(
% ERC
            (   (member(R,SepRows) ; member(C,SepCols))
% ERC
            ->  Cell = 0
% ERC
            ;   arc_grid_at(Grid,R,C,V0),
% ERC
                (   V0 \= 0, V0 \= Bg
% ERC
                ->  Cell = V0
% ERC
                ;   once((nth0(Rbi,RowBands,RBand), member(R,RBand),
% ERC
                          nth0(Wr,RBand,R))),
% ERC
                    once((nth0(Cbi,ColBands,CBand), member(C,CBand),
% ERC
                          nth0(Wc,CBand,C))),
% ERC
                    (   once((member(Rbi-Cbi1-Wr-Wc-PV, Markers),
% ERC
                              member(Rbi-Cbi2-Wr-Wc-PV, Markers),
% ERC
                              Cbi1 \= Cbi2))
% ERC
                    ->  Cell = PV
% ERC
                    ;   once((member(Rbi1-Cbi-Wr-Wc-PV, Markers),
% ERC
                              member(Rbi2-Cbi-Wr-Wc-PV, Markers),
% ERC
                              Rbi1 \= Rbi2))
% ERC
                    ->  Cell = PV
% ERC
                    ;   Cell = V0
% ERC
                    )
% ERC
                )
% ERC
            )
% ERC
        ), AllCols, OutRow)
% ERC
    ), AllRows, Out),
% ERC
    !.

% arc_w27_bands(+SepList, +Total, -Bands): split 1..Total by separator positions.
% ERC
arc_w27_bands(Seps, Total, Bands) :-
% ERC
    numlist(1, Total, All),
% ERC
    arc_w27_bands_(All, Seps, [], Bands).
% ERC
arc_w27_bands_([], _, Acc, Bands) :-
% ERC
    (Acc \= [] -> reverse(Acc, Band), Bands = [Band] ; Bands = []).
% ERC
arc_w27_bands_([H|T], Seps, Acc, Bands) :-
% ERC
    (   member(H, Seps)
% ERC
    ->  (   Acc \= []
% ERC
        ->  reverse(Acc, Band),
% ERC
            arc_w27_bands_(T, Seps, [], RestBands),
% ERC
            Bands = [Band|RestBands]
% ERC
        ;   arc_w27_bands_(T, Seps, [], Bands)
% ERC
        )
% ERC
    ;   arc_w27_bands_(T, Seps, [H|Acc], Bands)
% ERC
    ).

% extend_periodic_rows (d8c310e9): for each row, detect the period P of the
% non-zero prefix and tile that prefix to fill all NC columns.
% ERC
arc_named_rule(extend_periodic_rows).
% ERC
arc_transform(extend_periodic_rows, Grid, Out) :-
% ERC
    arc_grid_dims(Grid, NR, NC),
% ERC
    NR > 0, NR =< 30, NC > 0, NC =< 30,
% ERC
    numlist(1, NC, AllCols),
% ERC
    maplist([Row, OutRow]>>(
% ERC
        (   \+((member(Cv,Row), Cv \= 0))
% ERC
        ->  OutRow = Row
% ERC
        ;   arc_w27_row_period(Row, P),
% ERC
            maplist([C, Cell]>>(
% ERC
                Ci is ((C-1) mod P) + 1,
% ERC
                nth1(Ci, Row, Cell)
% ERC
            ), AllCols, OutRow)
% ERC
        )
% ERC
    ), Grid, Out),
% ERC
    !.

% arc_w27_row_period(+Row, -P): find smallest P such that Row[i] = Row[i-P]
% for all i >= P+1 (1-indexed) where Row[i-P] is within the non-zero prefix.
% ERC
arc_w27_row_period(Row, P) :-
% ERC
    length(Row, N),
% ERC
    findall(Li, (nth1(Li,Row,LV), LV \= 0), NZIdxs),
% ERC
    max_list(NZIdxs, LastNZ),
% ERC
    P1 is LastNZ - 1,
% ERC
    (P1 >= 1 -> numlist(1, P1, PCands) ; PCands = []),
% ERC
    once((
% ERC
        member(P, PCands),
% ERC
        \+((
% ERC
            numlist(1, LastNZ, Idxs),
% ERC
            member(I, Idxs), I > P,
% ERC
            Iprev is I - P,
% ERC
            nth1(I, Row, VI), nth1(Iprev, Row, VIprev),
% ERC
            VI \= VIprev
% ERC
        ))
% ERC
    )),
% ERC
    !.
% ERC
arc_w27_row_period(Row, P) :- length(Row, P).

% half_bottom_to_8 (ce9e57f2): for each active column (has some non-zero cells),
% replace the bottom floor(H/2) cells with 8, where H = span height of that column.
% ERC
arc_named_rule(half_bottom_to_8).
% ERC
arc_transform(half_bottom_to_8, Grid, Out) :-
% ERC
    arc_grid_dims(Grid, NR, NC),
% ERC
    NR > 0, NR =< 30, NC > 0, NC =< 30,
% ERC
    numlist(1, NR, AllRows), numlist(1, NC, AllCols),
% ERC
    maplist([C, CEight]>>(
% ERC
        findall(R, (member(R,AllRows), arc_grid_at(Grid,R,C,V), V \= 0), ActiveRs),
% ERC
        (   ActiveRs = []
% ERC
        ->  CEight = C-0-0
% ERC
        ;   min_list(ActiveRs, RMin), max_list(ActiveRs, RMax),
% ERC
            H is RMax - RMin + 1,
% ERC
            NEight is H // 2,
% ERC
            EightStart is RMax - NEight + 1,
% ERC
            CEight = C-EightStart-RMax
% ERC
        )
% ERC
    ), AllCols, EightInfos),
% ERC
    maplist([R, OutRow]>>(
% ERC
        maplist([C, Cell]>>(
% ERC
            member(C-ES-EM, EightInfos),
% ERC
            arc_grid_at(Grid,R,C,V0),
% ERC
            (   ES > 0, R >= ES, R =< EM, V0 \= 0
% ERC
            ->  Cell = 8
% ERC
            ;   Cell = V0
% ERC
            )
% ERC
        ), AllCols, OutRow)
% ERC
    ), AllRows, Out),
% ERC
    !.

% snake_cols_to_3col (cdecee7f): collect non-zero single-pixel cells, sort by
% column ascending, snake-fill into a fixed 3-row x 3-col output.
% ERC
arc_named_rule(snake_cols_to_3col).
% ERC
arc_transform(snake_cols_to_3col, Grid, Out) :-
% ERC
    arc_grid_dims(Grid, NR, NC),
% ERC
    NR > 0, NR =< 30, NC > 0, NC =< 30,
% ERC
    numlist(1, NR, AllRows), numlist(1, NC, AllCols),
% ERC
    findall(C-V, (member(R,AllRows), member(C,AllCols),
% ERC
        arc_grid_at(Grid,R,C,V), V \= 0), RawCells),
% ERC
    msort(RawCells, Cells),
% ERC
    Cells \= [],
% ERC
    numlist(1, 3, ThreeCols), numlist(1, 3, ThreeRows),
% ERC
    maplist([RowIdx, OutRow]>>(
% ERC
        maplist([ColIdx, Cell]>>(
% ERC
            Pos is (RowIdx-1)*3 + ColIdx - 1,
% ERC
            (   RowIdx mod 2 =:= 1
% ERC
            ->  ActualPos = Pos
% ERC
            ;   RowStart is (RowIdx-1)*3,
% ERC
                PosInRow is Pos - RowStart,
% ERC
                ActualPos is RowStart + (2 - PosInRow)
% ERC
            ),
% ERC
            (   ActualPos < 9,
% ERC
                nth0(ActualPos, Cells, _-V)
% ERC
            ->  Cell = V
% ERC
            ;   Cell = 0
% ERC
            )
% ERC
        ), ThreeCols, OutRow)
% ERC
    ), ThreeRows, Out),
% ERC
    !.

% zigzag_extend_rows (eb281b96): extend grid vertically as a zigzag; output has
% 4*(NR-1)+1 rows; row i maps to input row |((i-1) mod 2*(NR-1)) - (NR-1)| + ...
% (standard bounce formula).
% ERC
arc_named_rule(zigzag_extend_rows).
% ERC
arc_transform(zigzag_extend_rows, Grid, Out) :-
% ERC
    arc_grid_dims(Grid, NR, NC),
% ERC
    NR > 1, NR =< 10, NC > 0, NC =< 30,
% ERC
    OutNR is 4*(NR-1)+1,
% ERC
    Period is 2*(NR-1),
% ERC
    numlist(1, OutNR, OutRowIdxs),
% ERC
    maplist([I, Row]>>(
% ERC
        Pos is (I-1) mod Period,
% ERC
        (   Pos < NR
% ERC
        ->  SrcR is Pos + 1
% ERC
        ;   SrcR is Period - Pos + 1
% ERC
        ),
% ERC
        nth1(SrcR, Grid, Row)
% ERC
    ), OutRowIdxs, Out),
% ERC
    !.

% pick_hsym_shape (72ca375d): among distinct colored shapes in the grid, pick the
% one whose bounding box rows are all palindromes (horizontally symmetric).
% ERC
arc_named_rule(pick_hsym_shape).
% ERC
arc_transform(pick_hsym_shape, Grid, Out) :-
% ERC
    arc_grid_dims(Grid, NR, NC),
% ERC
    NR > 0, NR =< 30, NC > 0, NC =< 30,
% ERC
    numlist(1, NR, AllRows), numlist(1, NC, AllCols),
% ERC
    findall(V, (member(R,AllRows), member(C,AllCols),
% ERC
        arc_grid_at(Grid,R,C,V), V \= 0), Vals),
% ERC
    sort(Vals, Colors),
% ERC
    Colors \= [],
% ERC
    once((
% ERC
        member(Col, Colors),
% ERC
        findall(R-C, (member(R,AllRows), member(C,AllCols),
% ERC
            arc_grid_at(Grid,R,C,Col)), ColCells),
% ERC
        ColCells \= [],
% ERC
        findall(R, member(R-_,ColCells), Rs),
% ERC
        findall(C, member(_-C,ColCells), Cs),
% ERC
        min_list(Rs,R0), max_list(Rs,R1),
% ERC
        min_list(Cs,C0), max_list(Cs,C1),
% ERC
        numlist(R0,R1,BRows), numlist(C0,C1,BCols),
% ERC
        maplist([R, Row]>>(
% ERC
            maplist([C, Cell]>>(
% ERC
                arc_grid_at(Grid,R,C,V),
% ERC
                (V =:= Col -> Cell = Col ; Cell = 0)
% ERC
            ), BCols, Row)
% ERC
        ), BRows, Shape),
% ERC
        maplist([SRow]>>(SRow = SR, reverse(SR,SR)), Shape)
% ERC
    )),
% ERC
    maplist([R, Row]>>(
% ERC
        maplist([C, Cell]>>(
% ERC
            arc_grid_at(Grid,R,C,V),
% ERC
            (V =:= Col -> Cell = Col ; Cell = 0)
% ERC
        ), BCols, Row)
% ERC
    ), BRows, Out),
% ERC
    !.

% ---------------------------------------------------------------------------
% WAVE 28 RULES
% Eight new named rules solving 9 additional ARC-AGI-1 tasks.
% ---------------------------------------------------------------------------

% ERC
arc_named_rule(fill_rect_frame_124).
% ERC
arc_transform(fill_rect_frame_124, Grid, Out) :-
% ERC
    arc_grid_dims(Grid, NR, NC),
% ERC
    NR > 0, NR =< 30, NC > 0, NC =< 30,
% ERC
    numlist(1, NR, AllRows), numlist(1, NC, AllCols),
% ERC
    findall(R-C, (member(R,AllRows), member(C,AllCols),
% ERC
        arc_grid_at(Grid,R,C,5)), Fives),
% ERC
    Fives \= [],
% ERC
    arc_w28_rect_comps(Fives, Grid, NR, NC, Comps),
% ERC
    arc_w28_frame_apply(Grid, Comps, NR, NC, Out),
% ERC
    !.

% ERC
arc_w28_rect_comps([], _, _, _, []).
% ERC
arc_w28_rect_comps([R-C|Rest], Grid, NR, NC, [Comp|Comps]) :-
% ERC
    arc_w28_bfs5(Grid, NR, NC, [R-C], [], Comp),
% ERC
    subtract(Rest, Comp, Rest2),
% ERC
    arc_w28_rect_comps(Rest2, Grid, NR, NC, Comps).

% ERC
arc_w28_bfs5(_, _, _, [], Seen, Seen).
% ERC
arc_w28_bfs5(Grid, NR, NC, [R-C|Queue], Seen, Out) :-
% ERC
    ( member(R-C, Seen) ->
% ERC
        arc_w28_bfs5(Grid, NR, NC, Queue, Seen, Out)
% ERC
    ; R >= 1, R =< NR, C >= 1, C =< NC,
% ERC
      arc_grid_at(Grid, R, C, V), V =:= 5 ->
% ERC
        R1 is R+1, R2 is R-1, C1 is C+1, C2 is C-1,
% ERC
        findall(NR2-NC2, (member(NR2-NC2, [R1-C,R2-C,R-C1,R-C2]),
% ERC
            NR2 >= 1, NR2 =< NR, NC2 >= 1, NC2 =< NC,
% ERC
            arc_grid_at(Grid, NR2, NC2, 5)), Neighbors),
% ERC
        append(Queue, Neighbors, Queue2),
% ERC
        arc_w28_bfs5(Grid, NR, NC, Queue2, [R-C|Seen], Out)
% ERC
    ;   arc_w28_bfs5(Grid, NR, NC, Queue, Seen, Out)
% ERC
    ).

% ERC
arc_w28_frame_apply(Grid, [], NR, NC, Out) :-
% ERC
    numlist(1, NR, AllRows), numlist(1, NC, AllCols),
% ERC
    maplist([R, Row]>>(
% ERC
        maplist([C, V]>>(arc_grid_at(Grid,R,C,V)), AllCols, Row)
% ERC
    ), AllRows, Out).
% ERC
arc_w28_frame_apply(Grid, [Comp|Rest], NR, NC, Out) :-
% ERC
    findall(R, member(R-_, Comp), Rs),
% ERC
    findall(C, member(_-C, Comp), Cs),
% ERC
    min_list(Rs, Ra), max_list(Rs, Rb),
% ERC
    min_list(Cs, Ca), max_list(Cs, Cb),
% ERC
    arc_w28_frame_apply(Grid, Rest, NR, NC, TmpGrid),
% ERC
    numlist(1, NR, AllRows), numlist(1, NC, AllCols),
% ERC
    maplist([R, Row]>>(
% ERC
        maplist([C, V]>>(
% ERC
            ( R >= Ra, R =< Rb, C >= Ca, C =< Cb ->
% ERC
                ( (R =:= Ra ; R =:= Rb), (C =:= Ca ; C =:= Cb) -> V = 1
% ERC
                ; (R =:= Ra ; R =:= Rb ; C =:= Ca ; C =:= Cb) -> V = 4
% ERC
                ; V = 2
% ERC
                )
% ERC
            ;   arc_grid_at(TmpGrid,R,C,V)
% ERC
            )
% ERC
        ), AllCols, Row)
% ERC
    ), AllRows, Out).

% ERC
arc_named_rule(fill_two_rects_12).
% ERC
arc_transform(fill_two_rects_12, Grid, Out) :-
% ERC
    arc_grid_dims(Grid, NR, NC),
% ERC
    NR > 0, NR =< 30, NC > 0, NC =< 30,
% ERC
    numlist(1, NR, AllRows), numlist(1, NC, AllCols),
% ERC
    findall(R-C, (member(R,AllRows), member(C,AllCols),
% ERC
        arc_grid_at(Grid,R,C,4)), Fours),
% ERC
    Fours \= [],
% ERC
    arc_w28_rect_comps_val(Fours, Grid, NR, NC, 4, Comps),
% ERC
    length(Comps, 2),
% ERC
    Comps = [C1, C2],
% ERC
    length(C1, L1), length(C2, L2),
% ERC
    ( L1 >= L2 -> BigComp = C1, SmallComp = C2
% ERC
    ; BigComp = C2, SmallComp = C1
% ERC
    ),
% ERC
    arc_w28_rect_interior(BigComp, BigInterior),
% ERC
    arc_w28_rect_interior(SmallComp, SmallInterior),
% ERC
    numlist(1, NR, AllRows2), numlist(1, NC, AllCols2),
% ERC
    maplist([R, Row]>>(
% ERC
        maplist([C, V]>>(
% ERC
            ( member(R-C, BigInterior) -> V = 2
% ERC
            ; member(R-C, SmallInterior) -> V = 1
% ERC
            ; arc_grid_at(Grid,R,C,V)
% ERC
            )
% ERC
        ), AllCols2, Row)
% ERC
    ), AllRows2, Out),
% ERC
    !.

% ERC
arc_w28_rect_comps_val([], _, _, _, _, []).
% ERC
arc_w28_rect_comps_val([R-C|Rest], Grid, NR, NC, Val, [Comp|Comps]) :-
% ERC
    arc_w28_bfs_val(Grid, NR, NC, Val, [R-C], [], Comp),
% ERC
    subtract(Rest, Comp, Rest2),
% ERC
    arc_w28_rect_comps_val(Rest2, Grid, NR, NC, Val, Comps).

% ERC
arc_w28_bfs_val(_, _, _, _, [], Seen, Seen).
% ERC
arc_w28_bfs_val(Grid, NR, NC, Val, [R-C|Queue], Seen, Out) :-
% ERC
    ( member(R-C, Seen) ->
% ERC
        arc_w28_bfs_val(Grid, NR, NC, Val, Queue, Seen, Out)
% ERC
    ; R >= 1, R =< NR, C >= 1, C =< NC,
% ERC
      arc_grid_at(Grid, R, C, V), V =:= Val ->
% ERC
        R1 is R+1, R2 is R-1, C1 is C+1, C2 is C-1,
% ERC
        findall(NR2-NC2, (member(NR2-NC2, [R1-C,R2-C,R-C1,R-C2]),
% ERC
            NR2 >= 1, NR2 =< NR, NC2 >= 1, NC2 =< NC,
% ERC
            arc_grid_at(Grid, NR2, NC2, Val)), Neighbors),
% ERC
        append(Queue, Neighbors, Queue2),
% ERC
        arc_w28_bfs_val(Grid, NR, NC, Val, Queue2, [R-C|Seen], Out)
% ERC
    ;   arc_w28_bfs_val(Grid, NR, NC, Val, Queue, Seen, Out)
% ERC
    ).

% ERC
arc_w28_rect_interior(Comp, Interior) :-
% ERC
    findall(R, member(R-_, Comp), Rs),
% ERC
    findall(C, member(_-C, Comp), Cs),
% ERC
    min_list(Rs, Ra), max_list(Rs, Rb),
% ERC
    min_list(Cs, Ca), max_list(Cs, Cb),
% ERC
    Ra2 is Ra+1, Rb2 is Rb-1, Ca2 is Ca+1, Cb2 is Cb-1,
% ERC
    ( Ra2 =< Rb2, Ca2 =< Cb2 ->
% ERC
        numlist(Ra2, Rb2, InRows), numlist(Ca2, Cb2, InCols),
% ERC
        findall(R-C, (member(R,InRows), member(C,InCols)), Interior)
% ERC
    ;   Interior = []
% ERC
    ).

% ERC
arc_named_rule(extract_largest_blob).
% ERC
arc_transform(extract_largest_blob, Grid, Out) :-
% ERC
    arc_grid_dims(Grid, NR, NC),
% ERC
    NR > 0, NR =< 30, NC > 0, NC =< 30,
% ERC
    numlist(1, NR, AllRows), numlist(1, NC, AllCols),
% ERC
    findall(R-C, (member(R,AllRows), member(C,AllCols),
% ERC
        arc_grid_at(Grid,R,C,V), V \= 0), NZCells),
% ERC
    NZCells \= [],
% ERC
    arc_w28_all_blobs(NZCells, Grid, NR, NC, Blobs),
% ERC
    arc_w28_largest(Blobs, Largest),
% ERC
    findall(R, member(R-_, Largest), BlobRs),
% ERC
    findall(C, member(_-C, Largest), BlobCs),
% ERC
    min_list(BlobRs, R0), max_list(BlobRs, R1),
% ERC
    min_list(BlobCs, C0), max_list(BlobCs, C1),
% ERC
    numlist(R0, R1, OutRows), numlist(C0, C1, OutCols),
% ERC
    maplist([R, Row]>>(
% ERC
        maplist([C, V]>>(
% ERC
            ( member(R-C, Largest) -> arc_grid_at(Grid,R,C,V)
% ERC
            ; V = 0
% ERC
            )
% ERC
        ), OutCols, Row)
% ERC
    ), OutRows, Out),
% ERC
    !.

% ERC
arc_w28_all_blobs([], _, _, _, []).
% ERC
arc_w28_all_blobs([R-C|Rest], Grid, NR, NC, [Blob|Blobs]) :-
% ERC
    arc_grid_at(Grid, R, C, Val),
% ERC
    arc_w28_bfs_val(Grid, NR, NC, Val, [R-C], [], Blob),
% ERC
    subtract(Rest, Blob, Rest2),
% ERC
    arc_w28_all_blobs(Rest2, Grid, NR, NC, Blobs).

% ERC
arc_w28_largest([H|T], Largest) :-
% ERC
    arc_w28_largest_(T, H, Largest).
% ERC
arc_w28_largest_([], Best, Best).
% ERC
arc_w28_largest_([H|T], Best, Largest) :-
% ERC
    length(H, LH), length(Best, LB),
% ERC
    ( LH > LB -> arc_w28_largest_(T, H, Largest)
% ERC
    ; arc_w28_largest_(T, Best, Largest)
% ERC
    ).

% ERC
arc_named_rule(stamp_plus_cardinal).
% ERC
arc_transform(stamp_plus_cardinal, Grid, Out) :-
% ERC
    arc_grid_dims(Grid, NR, NC),
% ERC
    NR > 0, NR =< 30, NC > 0, NC =< 30,
% ERC
    numlist(1, NR, AllRows), numlist(1, NC, AllCols),
% ERC
    findall(R-C, (member(R,AllRows), member(C,AllCols),
% ERC
        arc_grid_at(Grid,R,C,1)), Ones),
% ERC
    Ones \= [],
% ERC
    maplist([R, Row]>>(
% ERC
        maplist([C, V]>>(
% ERC
            arc_grid_at(Grid, R, C, Orig),
% ERC
            ( Orig =:= 1 -> V = 1
% ERC
            ; once((
% ERC
                R1 is R+1, member(R1-C, Ones), V = 2
% ERC
              ; R1 is R-1, member(R1-C, Ones), V = 8
% ERC
              ; C1 is C+1, member(R-C1, Ones), V = 7
% ERC
              ; C1 is C-1, member(R-C1, Ones), V = 6
% ERC
              ; V = Orig
% ERC
              ))
% ERC
            )
% ERC
        ), AllCols, Row)
% ERC
    ), AllRows, Out),
% ERC
    !.

% ERC
arc_named_rule(hollow_sq_to_plus).
% ERC
arc_transform(hollow_sq_to_plus, Grid, Out) :-
% ERC
    arc_grid_dims(Grid, NR, NC),
% ERC
    NR > 0, NR =< 30, NC > 0, NC =< 30,
% ERC
    numlist(1, NR, AllRows), numlist(1, NC, AllCols),
% ERC
    findall(R-C, (member(R,AllRows), member(C,AllCols),
% ERC
        arc_grid_at(Grid,R,C,0),
% ERC
        R > 1, R < NR, C > 1, C < NC,
% ERC
        R00 is R-1, R11 is R+1, C00 is C-1, C11 is C+1,
% ERC
        arc_grid_at(Grid,R00,C00,1), arc_grid_at(Grid,R00,C,1),
% ERC
        arc_grid_at(Grid,R00,C11,1), arc_grid_at(Grid,R,C00,1),
% ERC
        arc_grid_at(Grid,R,C11,1), arc_grid_at(Grid,R11,C00,1),
% ERC
        arc_grid_at(Grid,R11,C,1), arc_grid_at(Grid,R11,C11,1)
% ERC
    ), Centers),
% ERC
    Centers \= [],
% ERC
    maplist([R, Row]>>(
% ERC
        maplist([C, V]>>(
% ERC
            arc_grid_at(Grid, R, C, Orig),
% ERC
            ( once((
% ERC
                member(CR-CC, Centers),
% ERC
                ( (R =:= CR, C =:= CC) -> true
% ERC
                ; (R =:= CR-1, C =:= CC) -> true
% ERC
                ; (R =:= CR+1, C =:= CC) -> true
% ERC
                ; (R =:= CR, C =:= CC-1) -> true
% ERC
                ; (R =:= CR, C =:= CC+1) -> true
% ERC
                )
% ERC
              )) -> V = 2
% ERC
            ; Orig =:= 1,
% ERC
              once((
% ERC
                member(CR-CC, Centers),
% ERC
                R00b is CR-1, R11b is CR+1, C00b is CC-1, C11b is CC+1,
% ERC
                member(R-C, [R00b-C00b, R00b-C11b, R11b-C00b, R11b-C11b])
% ERC
              )) -> V = 0
% ERC
            ; V = Orig
% ERC
            )
% ERC
        ), AllCols, Row)
% ERC
    ), AllRows, Out),
% ERC
    !.

% ERC
arc_named_rule(reflect_8_by_4_arrow).
% ERC
arc_transform(reflect_8_by_4_arrow, Grid, Out) :-
% ERC
    arc_grid_dims(Grid, NR, NC),
% ERC
    NR =:= 6, NC =:= 9,
% ERC
    numlist(1, NC, AllCols),
% ERC
    findall(C, (member(C, AllCols), arc_grid_at(Grid, 4, C, 4)), Row4Fours),
% ERC
    Row4Fours = [TabC|_],
% ERC
    numlist(1, NR, AllRows),
% ERC
    maplist([R, Row]>>(
% ERC
        maplist([C, V]>>(
% ERC
            arc_grid_at(Grid, R, C, Orig),
% ERC
            ( R =< 3, TabC =< 4,
% ERC
              C >= 1, C =< 3,
% ERC
              SrcC is 7 - C,
% ERC
              arc_grid_at(Grid, R, SrcC, 8) ->
% ERC
                V = 8
% ERC
            ; R =< 3, TabC >= 6,
% ERC
              C >= 7, C =< 9,
% ERC
              SrcC is 13 - C,
% ERC
              arc_grid_at(Grid, R, SrcC, 8) ->
% ERC
                V = 8
% ERC
            ; V = Orig
% ERC
            )
% ERC
        ), AllCols, Row)
% ERC
    ), AllRows, Out),
% ERC
    !.

% ERC
arc_named_rule(complete_4fold_rot_sym).
% ERC
arc_transform(complete_4fold_rot_sym, Grid, Out) :-
% ERC
    arc_grid_dims(Grid, NR, NC),
% ERC
    NR > 0, NR =< 30, NC > 0, NC =< 30,
% ERC
    numlist(1, NR, AllRows), numlist(1, NC, AllCols),
% ERC
    findall(R-C, (member(R,AllRows), member(C,AllCols),
% ERC
        arc_grid_at(Grid,R,C,V), V \= 0), NZCells),
% ERC
    NZCells \= [],
% ERC
    findall(R, member(R-_,NZCells), NZRs),
% ERC
    findall(C, member(_-C,NZCells), NZCs),
% ERC
    min_list(NZRs,Rmin), max_list(NZRs,Rmax),
% ERC
    min_list(NZCs,Cmin), max_list(NZCs,Cmax),
% ERC
    RSum is Rmin + Rmax, CSum is Cmin + Cmax,
% ERC
    0 is RSum mod 2, 0 is CSum mod 2,
% ERC
    CR is RSum // 2, CC is CSum // 2,
% ERC
    maplist([R, Row]>>(
% ERC
        maplist([C, V]>>(
% ERC
            arc_grid_at(Grid, R, C, Orig),
% ERC
            ( Orig \= 0 -> V = Orig
% ERC
            ;   DR is R - CR, DC is C - CC,
% ERC
                once((
% ERC
                    DR1 is CR - DC, DC1 is CC + DR,
% ERC
                    DR1 >= 1, DR1 =< NR, DC1 >= 1, DC1 =< NC,
% ERC
                    arc_grid_at(Grid, DR1, DC1, SV1), SV1 \= 0, V = SV1
% ERC
                ;   DR2 is CR*2 - R, DC2 is CC*2 - C,
% ERC
                    DR2 >= 1, DR2 =< NR, DC2 >= 1, DC2 =< NC,
% ERC
                    arc_grid_at(Grid, DR2, DC2, SV2), SV2 \= 0, V = SV2
% ERC
                ;   DR3 is CR + DC, DC3 is CC - DR,
% ERC
                    DR3 >= 1, DR3 =< NR, DC3 >= 1, DC3 =< NC,
% ERC
                    arc_grid_at(Grid, DR3, DC3, SV3), SV3 \= 0, V = SV3
% ERC
                ;   V = 0
% ERC
                ))
% ERC
            )
% ERC
        ), AllCols, Row)
% ERC
    ), AllRows, Out),
% ERC
    !.

% ERC
arc_named_rule(center_shape_at_3_anchor).
% ERC
arc_transform(center_shape_at_3_anchor, Grid, Out) :-
% ERC
    arc_grid_dims(Grid, NR, NC),
% ERC
    NR > 0, NR =< 30, NC > 0, NC =< 30,
% ERC
    numlist(1, NR, AllRows), numlist(1, NC, AllCols),
% ERC
    findall(R-C, (member(R,AllRows), member(C,AllCols),
% ERC
        arc_grid_at(Grid,R,C,3)), Anchors),
% ERC
    findall(R-C, (member(R,AllRows), member(C,AllCols),
% ERC
        arc_grid_at(Grid,R,C,2)), ShapeCells),
% ERC
    Anchors \= [], ShapeCells \= [],
% ERC
    findall(R, member(R-_,Anchors), ARs),
% ERC
    findall(C, member(_-C,Anchors), ACs),
% ERC
    findall(R, member(R-_,ShapeCells), SRs),
% ERC
    findall(C, member(_-C,ShapeCells), SCs),
% ERC
    min_list(ARs,ARmin), max_list(ARs,ARmax),
% ERC
    min_list(ACs,ACmin), max_list(ACs,ACmax),
% ERC
    min_list(SRs,SRmin), max_list(SRs,SRmax),
% ERC
    min_list(SCs,SCmin), max_list(SCs,SCmax),
% ERC
    ARS is ARmin + ARmax, ACS is ACmin + ACmax,
% ERC
    SRS is SRmin + SRmax, SCS is SCmin + SCmax,
% ERC
    0 is (ARS - SRS) mod 2, 0 is (ACS - SCS) mod 2,
% ERC
    DR is (ARS - SRS) // 2, DC is (ACS - SCS) // 2,
% ERC
    maplist([R, Row]>>(
% ERC
        maplist([C, V]>>(
% ERC
            arc_grid_at(Grid, R, C, Orig),
% ERC
            (   SR is R - DR, SC is C - DC,
% ERC
                SR >= 1, SR =< NR, SC >= 1, SC =< NC,
% ERC
                arc_grid_at(Grid, SR, SC, 2) ->
% ERC
                V = 2
% ERC
            ; Orig =:= 2 -> V = 0
% ERC
            ; Orig \= 0 -> V = Orig
% ERC
            ; V = 0
% ERC
            )
% ERC
        ), AllCols, Row)
% ERC
    ), AllRows, Out),
% ERC
    !.

% ---------------------------------------------------------------------------
% WAVE 29 HELPERS
% ---------------------------------------------------------------------------

% arc_w29_max_count_col/2: color with most occurrences; on tie, lowest value wins.
% ERC
arc_w29_max_count_col(AllVs, MainCol) :-
% ERC
    msort(AllVs, Sorted29),
% ERC
    sort(Sorted29, UniqueVs29),
% ERC
    maplist([V29, N29-V29]>>(include(=(V29), Sorted29, VL29), length(VL29, N29)), UniqueVs29, NVPairs29),
% ERC
    msort(NVPairs29, MSorted29),
% ERC
    last(MSorted29, MaxN29-_),
% ERC
    findall(MV29, member(MaxN29-MV29, MSorted29), MaxVs29),
% ERC
    min_list(MaxVs29, MainCol).

% arc_w29_cc_is_square/4: find an NxN square CC in Comps; returns TL and N.
% ERC
arc_w29_cc_is_square(Comps29, TL_R29, TL_C29, N29) :-
% ERC
    member(component(_, Cells29), Comps29),
% ERC
    length(Cells29, Sz29),
% ERC
    N29 is round(sqrt(float(Sz29))),
% ERC
    N29 >= 1, N29 * N29 =:= Sz29,
% ERC
    findall(R29, member(R29-_, Cells29), Rs29),
% ERC
    findall(C29, member(_-C29, Cells29), Cs29),
% ERC
    min_list(Rs29, TL_R29), max_list(Rs29, MaxR29),
% ERC
    min_list(Cs29, TL_C29), max_list(Cs29, MaxC29),
% ERC
    H29 is MaxR29 - TL_R29 + 1, H29 =:= N29,
% ERC
    W29 is MaxC29 - TL_C29 + 1, W29 =:= N29.

% arc_w29_iso_sq_cc/5: isolated (non-template) NxN square CC of color 2.
% ERC
arc_w29_iso_sq_cc(AllComps29, Template2s29, TL_R29, TL_C29, N29) :-
% ERC
    member(component(2, Cells29), AllComps29),
% ERC
    \+ (member(RC29, Cells29), member(RC29, Template2s29)),
% ERC
    length(Cells29, Sz29),
% ERC
    N29 is round(sqrt(float(Sz29))),
% ERC
    N29 >= 1, N29 * N29 =:= Sz29,
% ERC
    findall(R29, member(R29-_, Cells29), Rs29),
% ERC
    findall(C29, member(_-C29, Cells29), Cs29),
% ERC
    min_list(Rs29, TL_R29), max_list(Rs29, MaxR29),
% ERC
    min_list(Cs29, TL_C29), max_list(Cs29, MaxC29),
% ERC
    H29 is MaxR29 - TL_R29 + 1, H29 =:= N29,
% ERC
    W29 is MaxC29 - TL_C29 + 1, W29 =:= N29.

% arc_w29_col_color/2: maps 1-indexed column number to row fill color.
% ERC
arc_w29_col_color(1, 2).
% ERC
arc_w29_col_color(2, 4).
% ERC
arc_w29_col_color(3, 3).

% ---------------------------------------------------------------------------
% WAVE 29 RULE 1: draw_x_diagonals (623ea044)
% Single nonzero source cell (SR,SC,SV); output SV at all (R,C) where |R-SR|=|C-SC|.
% ---------------------------------------------------------------------------
% ERC
arc_named_rule(draw_x_diagonals).
% ERC
arc_transform(draw_x_diagonals, Grid, Out) :-
% ERC
    arc_grid_dims(Grid, NR, NC),
% ERC
    NR =< 30, NC =< 30,
% ERC
    numlist(1, NR, AllRows), numlist(1, NC, AllCols),
% ERC
    once((member(SR, AllRows), member(SC, AllCols), arc_grid_at(Grid, SR, SC, SV), SV \= 0)),
% ERC
    maplist([R, Row]>>(
% ERC
        maplist([C, Cel]>>(
% ERC
            AbsDR is abs(R - SR), AbsDC is abs(C - SC),
% ERC
            ( AbsDR =:= AbsDC -> Cel = SV ; Cel = 0 )
% ERC
        ), AllCols, Row)
% ERC
    ), AllRows, Out),
% ERC
    !.

% ---------------------------------------------------------------------------
% WAVE 29 RULE 2: fill_frame_gaps (4612dd53)
% Rows/cols with >=4 nonzero cells fill from global min_c to max_c / min_r to max_r.
% ---------------------------------------------------------------------------
% ERC
arc_named_rule(fill_frame_gaps).
% ERC
arc_transform(fill_frame_gaps, Grid, Out) :-
% ERC
    arc_grid_dims(Grid, NR, NC),
% ERC
    NR =< 30, NC =< 30,
% ERC
    numlist(1, NR, AllRows), numlist(1, NC, AllCols),
% ERC
    findall(Rnz, (member(Rnz, AllRows), member(Cnz, AllCols), arc_grid_at(Grid, Rnz, Cnz, Vnz), Vnz \= 0), NZRs),
% ERC
    findall(Cnz2, (member(Rnz2, AllRows), member(Cnz2, AllCols), arc_grid_at(Grid, Rnz2, Cnz2, Vnz2), Vnz2 \= 0), NZCs),
% ERC
    NZRs \= [],
% ERC
    min_list(NZRs, MinR), max_list(NZRs, MaxR),
% ERC
    min_list(NZCs, MinC), max_list(NZCs, MaxC),
% ERC
    findall(FrR, (
% ERC
        member(FrR, AllRows),
% ERC
        findall(CC2, (member(CC2, AllCols), arc_grid_at(Grid, FrR, CC2, VV2), VV2 \= 0), RowNZ2),
% ERC
        length(RowNZ2, RCnt2), RCnt2 >= 4
% ERC
    ), FrameRows),
% ERC
    findall(FrC, (
% ERC
        member(FrC, AllCols),
% ERC
        findall(RR2, (member(RR2, AllRows), arc_grid_at(Grid, RR2, FrC, VV3), VV3 \= 0), ColNZ2),
% ERC
        length(ColNZ2, CCnt2), CCnt2 >= 4
% ERC
    ), FrameCols),
% ERC
    maplist([R, Row]>>(
% ERC
        maplist([C, Cel]>>(
% ERC
            arc_grid_at(Grid, R, C, Orig),
% ERC
            ( Orig =:= 0,
% ERC
              ( ( member(R, FrameRows), C >= MinC, C =< MaxC )
% ERC
              ; ( member(C, FrameCols), R >= MinR, R =< MaxR ) ) ->
% ERC
                Cel = 2
% ERC
            ; Cel = Orig )
% ERC
        ), AllCols, Row)
% ERC
    ), AllRows, Out),
% ERC
    !.

% ---------------------------------------------------------------------------
% WAVE 29 RULE 3: scale_stamp_at_2_markers (447fd412)
% Template 1+2 pattern; stamp 1-shape scaled to isolated 2-cell block size.
% ---------------------------------------------------------------------------
% ERC
arc_named_rule(scale_stamp_at_2_markers).
% ERC
arc_transform(scale_stamp_at_2_markers, Grid, Out) :-
% ERC
    arc_grid_dims(Grid, NR, NC),
% ERC
    NR =< 30, NC =< 30,
% ERC
    numlist(1, NR, AllRows), numlist(1, NC, AllCols),
% ERC
    findall(R-C, (member(R, AllRows), member(C, AllCols), arc_grid_at(Grid, R, C, 1)), OneCells),
% ERC
    findall(R-C, (member(R, AllRows), member(C, AllCols), arc_grid_at(Grid, R, C, 2)), TwoCells),
% ERC
    OneCells \= [], TwoCells \= [],
% ERC
    findall(R-C, (
% ERC
        member(R-C, TwoCells),
% ERC
        member(R1-C1, OneCells), abs(R-R1) =< 2, abs(C-C1) =< 2
% ERC
    ), T2sRaw),
% ERC
    sort(T2sRaw, Template2s),
% ERC
    Template2s \= [],
% ERC
    findall(R-C, (
% ERC
        member(R-C, TwoCells),
% ERC
        \+ (member(R1-C1, OneCells), abs(R-R1) =< 2, abs(C-C1) =< 2)
% ERC
    ), Iso2s),
% ERC
    Iso2s \= [],
% ERC
    msort(Template2s, [T2A_R-T2A_C | _]),
% ERC
    findall(DR-DC, (member(R-C, OneCells), DR is R - T2A_R, DC is C - T2A_C), RelOnes),
% ERC
    findall(DR-DC, (member(R-C, Template2s), DR is R - T2A_R, DC is C - T2A_C), RelTwosRaw),
% ERC
    msort(RelTwosRaw, RelTwos),
% ERC
    arc_connected_components(Grid, AllComps),
% ERC
    length(RelTwos, K),
% ERC
    ( K =:= 1 ->
% ERC
        findall(SR-SC, (
% ERC
            arc_w29_iso_sq_cc(AllComps, Template2s, TL_R, TL_C, N2),
% ERC
            member(DR-DC, RelOnes),
% ERC
            StartR is TL_R + DR * N2, StartC is TL_C + DC * N2,
% ERC
            N2_1 is N2 - 1,
% ERC
            between(0, N2_1, DI), between(0, N2_1, DJ),
% ERC
            SR is StartR + DI, SC is StartC + DJ,
% ERC
            SR >= 1, SR =< NR, SC >= 1, SC =< NC
% ERC
        ), StampCells0)
% ERC
    ; K =:= 2,
% ERC
      RelTwos = [_-_, DR2-DC2],
% ERC
      findall(SR-SC, (
% ERC
          arc_w29_iso_sq_cc(AllComps, Template2s, A_R, A_C, N2),
% ERC
          PairR is A_R + DR2 * N2, PairC is A_C + DC2 * N2,
% ERC
          arc_w29_iso_sq_cc(AllComps, Template2s, PairR, PairC, N2),
% ERC
          member(DR-DC, RelOnes),
% ERC
          StartR is A_R + DR * N2, StartC is A_C + DC * N2,
% ERC
          N2_1 is N2 - 1,
% ERC
          between(0, N2_1, DI), between(0, N2_1, DJ),
% ERC
          SR is StartR + DI, SC is StartC + DJ,
% ERC
          SR >= 1, SR =< NR, SC >= 1, SC =< NC
% ERC
      ), StampCells0)
% ERC
    ),
% ERC
    sort(StampCells0, StampCells),
% ERC
    maplist([R, Row]>>(
% ERC
        maplist([C, Cel]>>(
% ERC
            ( member(R-C, StampCells) -> Cel = 1
% ERC
            ; arc_grid_at(Grid, R, C, Cel) )
% ERC
        ), AllCols, Row)
% ERC
    ), AllRows, Out),
% ERC
    !.

% ---------------------------------------------------------------------------
% WAVE 29 RULE 4: four_way_reflect (4938f0c2, 4c5c2cf0)
% Main color (most cells; tie->lowest value) reflected 3 ways across marker center.
% ---------------------------------------------------------------------------
% ERC
arc_named_rule(four_way_reflect).
% ERC
arc_transform(four_way_reflect, Grid, Out) :-
% ERC
    arc_grid_dims(Grid, NR, NC),
% ERC
    NR =< 30, NC =< 30,
% ERC
    numlist(1, NR, AllRows), numlist(1, NC, AllCols),
% ERC
    findall(V, (member(R, AllRows), member(C, AllCols), arc_grid_at(Grid, R, C, V), V \= 0), AllVs),
% ERC
    AllVs \= [],
% ERC
    arc_w29_max_count_col(AllVs, MainCol),
% ERC
    findall(R-C, (member(R, AllRows), member(C, AllCols), arc_grid_at(Grid, R, C, MainCol)), MainCells),
% ERC
    findall(R-C, (
% ERC
        member(R, AllRows), member(C, AllCols),
% ERC
        arc_grid_at(Grid, R, C, MV), MV \= 0, MV \= MainCol
% ERC
    ), MarkerCells),
% ERC
    MarkerCells \= [],
% ERC
    findall(MR, member(MR-_, MarkerCells), MRs),
% ERC
    findall(MC, member(_-MC, MarkerCells), MCs),
% ERC
    min_list(MRs, MMinR), max_list(MRs, MMaxR),
% ERC
    min_list(MCs, MMinC), max_list(MCs, MMaxC),
% ERC
    SumR2 is MMinR + MMaxR,
% ERC
    SumC2 is MMinC + MMaxC,
% ERC
    maplist([R, Row]>>(
% ERC
        maplist([C, Cel]>>(
% ERC
            arc_grid_at(Grid, R, C, Orig),
% ERC
            ReflC is SumC2 - C, ReflR is SumR2 - R,
% ERC
            ( member(R-C, MainCells) -> Cel = MainCol
% ERC
            ; member(R-ReflC, MainCells) -> Cel = MainCol
% ERC
            ; member(ReflR-C, MainCells) -> Cel = MainCol
% ERC
            ; member(ReflR-ReflC, MainCells) -> Cel = MainCol
% ERC
            ; Cel = Orig )
% ERC
        ), AllCols, Row)
% ERC
    ), AllRows, Out),
% ERC
    !.

