arc_transform(shoot_isolated_into_8block, Grid, Out) :-
% ERC
    arc_grid_dims(Grid, NR, NC),
% ERC
    NR =< 30, NC =< 30,
% ERC
    numlist(1, NR, AllRows), numlist(1, NC, AllCols),
